package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.service.APKConstant2Service;
import be.schaubroeck.lpb.tools.service.APKConstantService;
import be.schaubroeck.lpb.tools.service.APKPrincipeService;
import be.schaubroeck.lpb.tools.service.AkeVervalService;
import be.schaubroeck.lpb.tools.service.BasisAardKodeExtensieService;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.service.DmfaVerminderingsPercentageService;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.FiscaleConstantService;
import be.schaubroeck.lpb.tools.service.LooncodeInclusiefService;
import be.schaubroeck.lpb.tools.service.OnthaalOudersWerkbonusService;
import be.schaubroeck.lpb.tools.service.RegimeRszppoService;
import be.schaubroeck.lpb.tools.service.RszConstantOldService;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import be.schaubroeck.lpb.tools.service.RszPlafondPercentageService;
import be.schaubroeck.lpb.tools.service.SchaalDefinitieService;
import be.schaubroeck.lpb.tools.service.SchaalVerhogingService;
import be.schaubroeck.lpb.tools.service.SchaalVersieService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;


public class StandaardNlpGlobalService implements NlpGlobalService {

    @Autowired
    @Qualifier("cachedConstantService")
    private ConstantService constantService;
    @Autowired
    private OnthaalOudersWerkbonusService onthaalOudersWerkbonusService;
    @Autowired
    @Qualifier("cachedRszConstantService")
    private RszConstantService rszConstantService;
    @Autowired
    @Qualifier("cachedRszConstantOldService")
    private RszConstantOldService rszConstantOldService;
    @Autowired
    @Qualifier("cachedDmfapplBasisBijdrageService")
    private DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    @Autowired
    private AardKodeExtensieFacade aardKodeExtensieFacade;
    @Autowired
    @Qualifier("cachedLooncodeInclusiefService")
    private LooncodeInclusiefService looncodeInclusiefService;
    @Autowired
    @Qualifier("cachedFiscaleConstantService")
    private FiscaleConstantService fiscaleConstantService;
    @Autowired
    @Qualifier("cachedApkPrincipeService")
    private APKPrincipeService apkPrincipeService;
    @Autowired
    @Qualifier("cachedApkConstantService")
    private APKConstantService apkConstantService;
    @Autowired
    @Qualifier("cachedApkConstant2Service")
    private APKConstant2Service apkConstant2Service;
    @Autowired
    @Qualifier("cachedRegimeRszppoService")
    private RegimeRszppoService regimeRszppoService;
    @Autowired
    @Qualifier("cachedRegimeApkRszppoService")
    private RegimeRszppoService regimeApkRszppoService;
    @Autowired
    @Qualifier("cachedAkeVervalService")
    private AkeVervalService akeVervalService;
    @Autowired
    @Qualifier("cachedDmfaVerminderingsPercentageService")
    private DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService;
    @Autowired
    @Qualifier("cachedBasisAardKodeExtensieService")
    private BasisAardKodeExtensieService basisAardKodeExtensieService;
    @Autowired
    private SchaalDefinitieService schaalDefinitieService;
    @Autowired
    private SchaalVerhogingService schaalVerhogingService;
    @Autowired
    private SchaalVersieService schaalVersieService;
    @Autowired
    @Qualifier("cachedRszPlafondPercentageService")
    private RszPlafondPercentageService rszPlafondPercentageService;

    @Override
    public ConstantService getConstantService() {
        return constantService;
    }

    @Override
    public OnthaalOudersWerkbonusService getOnthaalOudersWerkbonusService() {
        return onthaalOudersWerkbonusService;
    }

    @Override
    public DmfapplBasisBijdrageService getDmfapplBasisBijdrageService() {
        return dmfapplBasisBijdrageService;
    }

    @Override
    public AardKodeExtensieFacade getAardKodeExtensieFacade() {
        return aardKodeExtensieFacade;
    }

    @Override
    public LooncodeInclusiefService getLooncodeInclusiefService() {
        return looncodeInclusiefService;
    }

    @Override
    public FiscaleConstantService getFiscaleConstantService() {
        return fiscaleConstantService;
    }

    @Override
    public APKPrincipeService getApkPrincipeService() {
        return apkPrincipeService;
    }

    @Override
    public RegimeRszppoService getRegimeRszppoService() {
        return regimeRszppoService;
    }

    @Override
    public RegimeRszppoService getRegimeApkRszppoService() {
        return regimeApkRszppoService;
    }

    @Override
    public RszConstantService getRszConstantService() {
        return rszConstantService;
    }

    @Override
    public RszConstantOldService getRszConstantOldService() {
        return rszConstantOldService;
    }

    @Override
    public APKConstantService getApkConstantService() {
        return apkConstantService;
    }

    @Override
    public APKConstant2Service getApkConstant2Service() {
        return apkConstant2Service;
    }

    @Override
    public AkeVervalService getAkeVervalService() {
        return akeVervalService;
    }

    @Override
    public DmfaVerminderingsPercentageService getDmfaVerminderingsPercentageService() {
        return dmfaVerminderingsPercentageService;
    }

    @Override
    public BasisAardKodeExtensieService getBasisAardKodeExtensieService() {
        return basisAardKodeExtensieService;
    }

    @Override
    public SchaalVersieService getSchaalVersieService() {
        return schaalVersieService;
    }

    @Override
    public SchaalDefinitieService getSchaalDefinitieService() {
        return schaalDefinitieService;
    }

    @Override
    public RszPlafondPercentageService getRszPlafondPercentageService() {
        return rszPlafondPercentageService;
    }

    @Override
    public SchaalVerhogingService getSchaalVerhogingService() {
        return schaalVerhogingService;
    }

    @Override
    public void setSchaalVerhogingService(SchaalVerhogingService schaalVerhogingService) {
        this.schaalVerhogingService = schaalVerhogingService;
    }
}
